SELECT SUM(CS.[DAILY_COMMENTS]) AS WEEKLY_COMMENTS,
	SUM(CS.[DAILY_APPROVED]) AS WEEKLY_APPROVED,
	SUM(CS.[DAILY_SPAM]) AS WEEKLY_SPAM 
